mapper.select:
SELECT * FROM ( SELECT s.staff_id AS staffId, s.full_name AS fullName, s.duty_code AS dutyCode FROM CMH.STAFF s WHERE 1 = 1
AND s.staff_id LIKE #{staffIdPrefix} || '%'
AND s.duty_code IN
#{dutyCode}
AND ( UPPER(s.staff_id) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(s.full_name) LIKE '%' || UPPER(#{keyword}) || '%' OR UPPER(s.duty_code) LIKE '%' || UPPER(#{keyword}) || '%' )
ORDER BY s.full_name ASC, s.staff_id ASC ) WHERE ROWNUM <= #{limit}
